import { APIGatewayProxyEvent, APIGatewayProxyResult } from 'aws-lambda';
import { Project } from '../models/project';
import { ProjectService } from '../services/projectService';

export class ProjectHandler {
  private projectService: ProjectService;

  constructor(projectService: ProjectService) {
    this.projectService = projectService;
  }

  async createProject(event: APIGatewayProxyEvent): Promise<APIGatewayProxyResult> {
    try {
      const projectData = event.body ? JSON.parse(event.body) : undefined;
      const project: Project = await this.projectService.createProject(projectData);

      return {
        statusCode: 201,
        body: JSON.stringify({
          projectId: project.id,
          message: 'Project created successfully',
        }),
      };
    } catch (error) {
      return {
        statusCode: 500,
        body: JSON.stringify({
          message: 'An error occurred while creating the project',
          error: error.message,
        }),
      };
    }
  }
}
