import { APIGatewayProxyEvent, APIGatewayProxyResult } from "aws-lambda";
import { FormService } from "../services/formService";
import { FormServiceImpl } from "../services/formServiceImpl";

class FormHandler {
  private formService: FormService;

  constructor() {
    this.formService = new FormServiceImpl();
  }

  async getForm(event: APIGatewayProxyEvent): Promise<APIGatewayProxyResult> {
    try {
      const projectId = event.pathParameters?.projectId;

      if (!projectId) {
        return {
          statusCode: 400,
          body: JSON.stringify({ message: "Project ID is missing in the request" }),
        };
      }

      const form = await this.formService.getForm(projectId);

      if (!form) {
        return {
          statusCode: 404,
          body: JSON.stringify({ message: "Form not found" }),
        };
      }

      return {
        statusCode: 200,
        body: JSON.stringify(form),
      };
    } catch (error) {
      return {
        statusCode: 500,
        body: JSON.stringify({ message: "Internal server error" }),
      };
    }
  }
}

