import { ErrorInfo } from "../utils/validation";

export class Form {
  projectId: string;
  data: any;

  constructor(projectId: string, data: any) {
    this.projectId = projectId;
    this.data = data;
  }

  static fromJSON(json: string): Form {
    const data = JSON.parse(json);
    return new Form(data.projectId, data.data);
  }

  toJSON(): string {
    return JSON.stringify({
      projectId: this.projectId,
      data: this.data,
    });
  }

  addError(fieldName: string, errorMsg: string): void {
    const field = this.data.find((field: any) => field.key === fieldName);
    if (field) {
      field.error = ErrorInfo.createErrorInfo(fieldName, errorMsg);
    }
  }

  clearError(fieldName: string): void {
    const field = this.data.find((field: any) => field.key === fieldName);
    if (field) {
      field.error = null;
    }
  }
}

import { Form } from "../models/form";
import { ErrorInfo } from "../models/errorInfo";

export function validateForm(form: Form): boolean {
  let isValid = true;

  form.data.forEach((field: any) => {
    if (field.required && !field.value) {
      isValid = false;
      field.error = generateErrorInfo(field.key, "This field is required.");
    }
  });

  return isValid;
}

export function generateErrorInfo(fieldName: string, errorMsg: string): ErrorInfo {
  return { fieldName, message: errorMsg };
}

import fs from "fs";
import path from "path";

const translationsDirectory = path.resolve(__dirname, "../translations");

interface Translations {
  [key: string]: string;
}

const loadTranslations = (lang: string): Translations => {
  const filePath = path.resolve(translationsDirectory, `${lang}.json`);
  try {
    const rawData = fs.readFileSync(filePath, { encoding: "utf-8" });
    return JSON.parse(rawData);
  } catch (error) {
    throw new Error(`Failed to load translations for language: ${lang}`);
  }
};

const cache: { [key: string]: Translations } = {};

const getTranslations = (lang: string): Translations => {
  if (!cache[lang]) {
    cache[lang] = loadTranslations(lang);
  }
  return cache[lang];
};

function translate(key: string, lang: string): string {
  const translations = getTranslations(lang);
  if (!translations[key]) {
    throw new Error(`Translation not found for key: ${key} in language: ${lang}`);
  }
  return translations[key];
}

export default translate;

import * as cdk from '@aws-cdk/core';
import * as lambda from '@aws-cdk/aws-lambda';
import * as apigateway from '@aws-cdk/aws-apigateway';

export class QuirkyServerlessCodeGenieStack extends cdk.Stack {
  constructor(scope: cdk.Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // Lambda function for projectHandler
    const projectHandlerLambda = new lambda.Function(this, 'ProjectHandlerLambda', {
      runtime: lambda.Runtime.NODEJS_14_X,
      handler: 'src/handlers/projectHandler.createProject',
      code: lambda.Code.fromAsset('src'),
    });

    // Lambda function for formHandler
    const formHandlerLambda = new lambda.Function(this, 'FormHandlerLambda', {
      runtime: lambda.Runtime.NODEJS_14_X,
      handler: 'src/handlers/formHandler.getForm',
      code: lambda.Code.fromAsset('src'),
    });

    // API Gateway
    const api = new apigateway.RestApi(this, 'QuirkyServerlessCodeGenieApi', {
      restApiName: 'Quirky Serverless Code Genie API',
    });

    // API Gateway resources
    const projects = api.root.addResource('projects');
    const form = projects.addResource('form');

    // API Gateway integration with Lambda functions
    const projectHandlerIntegration = new apigateway.LambdaIntegration(projectHandlerLambda);
    const formHandlerIntegration = new apigateway.LambdaIntegration(formHandlerLambda);

    // API Gateway methods
    projects.addMethod('POST', projectHandlerIntegration);
    form.addMethod('GET', formHandlerIntegration);

    // API key
    const apiKey = api.addApiKey('ApiKey');

    // Usage plan for the API key
    const usagePlan = api.addUsagePlan('UsagePlan', {
      name: 'QuirkyCodeGenieUsagePlan',
      apiKey: apiKey,
      throttle: {
        rateLimit: 10,
        burstLimit: 2,
      },
    });

    // Connect usage plan with the API methods
    usagePlan.addApiStage({
      stage: api.deploymentStage,
      throttle: [
        {
          method: projects.methods[0],
          throttle: {
            rateLimit: 10,
            burstLimit: 2,
          },
        },
        {
          method: form.methods[0],
          throttle: {
            rateLimit: 10,
            burstLimit: 2,
          },
        },
      ],
    });
  }
}

